import MainHeader from "../MainHeader/MainHeader";
import classes from "./Chat.module.css";
import ChatForm from "./ChatForm";
import ChatMessages from "./ChatMessages";
import Avatar from "../UI/Avatar";

const Chat = () => {
  return (
    <div className={`${classes["chat-page"]} ${classes["container"]}`}>
      <MainHeader
        title="Friends"
        icon={
          <Avatar image="https://animedao.to/images/call-of-the-night.jpg"></Avatar>
        }
        tabBar={false}
      ></MainHeader>
      <ChatMessages></ChatMessages>
      <ChatForm></ChatForm>
    </div>
  );
};

export default Chat;
